  stimulus_type = NULL,
  options = '[{"id":"A","text":"eliminates the need for a complex dietary model for the consumer.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"makes it easier for consumers to understand the importance of a balanced diet.","is_correct":true,"explanation":"The text states that the USDA replaced the pyramid with a plate because it \"makes it easier for consumers to understand the importance of a balanced diet.\" This change is reflected in the use of a plate to visually represent the five food groups rather than a pyramid that depicts them in proportion. Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"provides a more accurate representation of the food groups that people should eat each day.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"reinforces the idea that fats, oils, and sweets are an important part of a balanced diet.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
