UPDATE public.questions SET
  stimulus_text = 'In the early 1900s, a new movement in art emerged called Dadaism. Dadaists rejected traditional art forms and sought to create art that was nonsensical and often provocative. One of the key figures of the Dada movement was the artist Marcel Duchamp, whose work is known for its playful and sometimes shocking nature. In 1917, Duchamp submitted a porcelain urinal to an art exhibition under the name “Fountain.” The urinal was rejected by the organizers of the exhibition, but it has since become one of the most famous works of Dada art. Duchamp’s work, and Dadaism in general, challenged the traditional values of art and challenged the very definition of what art could be.',
  question_text = 'According to the passage, what was the main purpose of the Dada movement?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"To create a new art form that was more beautiful and pleasing to the eye.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"To create a new art form that was more meaningful and profound.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"To create a new art form that was more accessible and popular.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"To create a new art form that was more nonsensical and provocative.","is_correct":true,"explanation":"The passage states that Dadaists sought to create art that was “nonsensical and often provocative.”  The passage also states that Duchamp’s work “challenged the traditional values of art and challenged the very definition of what art could be.” Thus, the main purpose of the Dada movement was to crea. Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'D',
