UPDATE public.questions SET
  stimulus_text = 'In the passage, the author discusses how people sometimes behave in ways that are inconsistent with their own best interests. For example, the author notes that people often avoid making decisions, even when those decisions could lead to positive outcomes. The author also suggests that people sometimes seek out information that is irrelevant to their needs, which can result in wasted time and effort. What is the author’s main point in this passage?',
